import{_ as e,c as a,a3 as i,o}from"./chunks/framework.BDUoXecB.js";const s="/coding-standards/assets/vscode_git_clone1.qDoYJxim.png",r="/coding-standards/assets/vscode_git_clone2.CEP9JvgJ.png",c="/coding-standards/assets/vscode_git_graph1.B-QqvDRT.png",l="/coding-standards/assets/vscode_git_graph2.004hjEVr.png",n="/coding-standards/assets/vscode_git_fetch1.DRikG15J.png",d="/coding-standards/assets/vscode_git_fetch2.DAVY-Tc0.png",g="/coding-standards/assets/vscode_git_branch1.l8tVcgzj.png",h="/coding-standards/assets/vscode_git_branch2.Cwy7x_5O.png",p="/coding-standards/assets/vscode_git_stage.BcG6O3Ku.png",u="/coding-standards/assets/vscode_git_commit.BYQAFQn8.png",m="/coding-standards/assets/vscode_git_push1.BlFN6oO1.png",_="/coding-standards/assets/vscode_git_push2.BhX_AasB.png",C="/coding-standards/assets/vscode_git_push3.DjxvPuCO.png",B=JSON.parse('{"title":"VSCode上でのGit操作","description":"","frontmatter":{"sidebarDepth":4,"title":"VSCode上でのGit操作","author":"フューチャー株式会社"},"headers":[],"relativePath":"documents/forGitBranch/vscode_git_ope.md","filePath":"documents/forGitBranch/vscode_git_ope.md"}'),b={name:"documents/forGitBranch/vscode_git_ope.md"};function f(O,t,q,v,G,k){return o(),a("div",null,t[0]||(t[0]=[i('<h2 id="vscode上でのgit操作" tabindex="-1">VSCode上でのGit操作 <a class="header-anchor" href="#vscode上でのgit操作" aria-label="Permalink to &quot;VSCode上でのGit操作&quot;">​</a></h2><p>利用頻度が高いとされるVS CodeでのGit操作を紹介する。</p><p>VSCode上でのGit操作は、サイドバーの &quot;Source Control&quot; から行うことができる。ほとんど全ての操作はコマンドパレットからも実行可能だが、説明は割愛する。</p><h3 id="推奨する拡張機能" tabindex="-1">推奨する拡張機能 <a class="header-anchor" href="#推奨する拡張機能" aria-label="Permalink to &quot;推奨する拡張機能&quot;">​</a></h3><p>GUIでのGit操作にあたり、次の2つの拡張機能をインストールしておくと利便性が高い。業務上はほぼ必須と見て良い。</p><ul><li><a href="https://marketplace.visualstudio.com/items?itemName=eamodio.gitlens" target="_blank" rel="noreferrer">GitLens</a><ul><li>Gitに関する様々な機能を提供する拡張機能</li><li>詳細：: <a href="https://future-architect.github.io/articles/%EF%BC%8920240415a/" target="_blank" rel="noreferrer">VSCodeでGitLensを使う - フューチャー技術ブログ</a></li></ul></li><li><a href="https://marketplace.visualstudio.com/items?itemName=mhutchie.git-graph" target="_blank" rel="noreferrer">Git Graph</a><ul><li>コミットグラフを表示する拡張機能</li><li>GitLensにもコミットグラフはありますが、Pro（有料版）限定の提供のため、ここではこちらの拡張機能を使用する</li></ul></li></ul><p>以降では、これらの拡張機能がインストールされていることを前提に説明を行う。</p><h3 id="リポジトリのクローン-git-clone" tabindex="-1">リポジトリのクローン (<code>git clone</code>) <a class="header-anchor" href="#リポジトリのクローン-git-clone" aria-label="Permalink to &quot;リポジトリのクローン (`git clone`)&quot;">​</a></h3><p>サイドバー &gt; Explorer か Source Control &gt; Clone Repository ボタンをクリックし、URLを入力すると、リポジトリをクローンできる。</p><p><img src="'+s+'" alt="Clone1"> <img src="'+r+'" alt="Clone2"></p><h3 id="コミットグラフの表示" tabindex="-1">コミットグラフの表示 <a class="header-anchor" href="#コミットグラフの表示" aria-label="Permalink to &quot;コミットグラフの表示&quot;">​</a></h3><p>SOURCE CONTROL パネル &gt; 黒丸のグラフアイコン (View Git Graph (git log)) をクリックすると、コミットグラフを表示できる。</p><p>白丸のグラフアイコン (Show Commit Graph) はGitLensのコミットグラフだが、冒頭の記述通り、Pro版でのみの提供となる。</p><p><img src="'+c+'" alt="Graph1"> <img src="'+l+'" alt="Graph2"></p><h3 id="リモートのフェッチ-プル-git-fetch-git-pull" tabindex="-1">リモートのフェッチ／プル (<code>git fetch</code> / <code>git pull</code>) <a class="header-anchor" href="#リモートのフェッチ-プル-git-fetch-git-pull" aria-label="Permalink to &quot;リモートのフェッチ／プル (`git fetch` / `git pull`)&quot;">​</a></h3><p>以下のいずれかの操作を実行すると、リモートリポジトリをフェッチできる。</p><ul><li>SOURCE CONTROL パネル &gt; 三点リーダーアイコン (More Actions...) をクリックし、 Fetch を選択</li><li>コミットグラフ &gt; 雲アイコン (Fetch from Remote(s)) をクリック</li></ul><p><img src="'+n+'" alt="Fetch1"></p><p>なお、フェッチ後に以下のようなダイアログが表示される場合があるが、 &quot;Yes&quot; を選択すると、自動で定期的にフェッチを行う。</p><p><img src="'+d+'" alt="Fetch2"></p><p>[TODO] プルを追記する。</p><h3 id="ブランチの作成-チェックアウト-git-branch-git-checkout" tabindex="-1">ブランチの作成／チェックアウト (<code>git branch</code> / <code>git checkout</code>) <a class="header-anchor" href="#ブランチの作成-チェックアウト-git-branch-git-checkout" aria-label="Permalink to &quot;ブランチの作成／チェックアウト (`git branch` / `git checkout`)&quot;">​</a></h3><p>以下のいずれかの操作を実行すると、ブランチを作成できる。</p><ul><li>SOURCE CONTROL パネル &gt; 三点リーダーアイコン (More Actions...) をクリックし、Branch &gt; Create Branch... を選択 <ul><li>現在チェックアウトしているブランチから新規ブランチが作成されますが、Create Branch From... を選択すると、作成元のブランチを選択することができる</li><li>作成したブランチに自動的にチェックアウトする</li></ul></li><li>コミットグラフ &gt; 作成元コミットの行上で右クリックし、Create Branch... を選択 <ul><li>&quot;Check out&quot; にチェックを入れると、作成したブランチにチェックアウトする</li></ul></li></ul><p><img src="'+g+'" alt="Branch1"> <img src="'+h+'" alt="Branch2"></p><p>[TODO] チェックアウトを追記する。</p><h3 id="ステージ-コミット-プッシュ-git-add-git-commit-git-push" tabindex="-1">ステージ／コミット／プッシュ (<code>git add</code> / <code>git commit</code> / <code>git push</code>) <a class="header-anchor" href="#ステージ-コミット-プッシュ-git-add-git-commit-git-push" aria-label="Permalink to &quot;ステージ／コミット／プッシュ (`git add` / `git commit` / `git push`)&quot;">​</a></h3><p>SOURCE CONTROL パネル &gt; 変更ファイルの行 &gt; +アイコン (Stage Changes) をクリックすると、対象ファイルをステージできる。（Changes &gt; +アイコン (Stage All Changes) をクリックすると、すべての変更をステージする）</p><p><img src="'+p+'" alt="Stage"></p><p>必要な変更をステージ後、 SOURCE CONTROL パネル内でコミットメッセージを入力し、 Commit ボタンをクリックすると、コミットを作成できる。</p><p><img src="'+u+'" alt="Commit"></p><p>以下のいずれかの操作を実行すると、作成したコミットをリモートリポジトリにプッシュできる。</p><ul><li>SOURCE CONTROL パネル &gt; 三点リーダーアイコン (More Actions...) をクリックし、Push を選択</li><li>BRANCHES パネル &gt; 対象ブランチの行 &gt; 雲アイコン (Publish Branch) をクリック</li><li>コミットグラフ &gt; 対象ブランチの上で右クリックし、Push Branch... を選択</li></ul><p><img src="'+m+'" alt="push1"> <img src="'+_+'" alt="push2"> <img src="'+C+'" alt="push3"></p><h3 id="リバート-git-revert" tabindex="-1">リバート (<code>git revert</code>) <a class="header-anchor" href="#リバート-git-revert" aria-label="Permalink to &quot;リバート (`git revert`)&quot;">​</a></h3><p>TODO</p><h3 id="マージ-git-merge" tabindex="-1">マージ (<code>git merge</code>) <a class="header-anchor" href="#マージ-git-merge" aria-label="Permalink to &quot;マージ (`git merge`)&quot;">​</a></h3><p>TODO</p><h3 id="リベース-git-rebase" tabindex="-1">リベース (<code>git rebase</code>) <a class="header-anchor" href="#リベース-git-rebase" aria-label="Permalink to &quot;リベース (`git rebase`)&quot;">​</a></h3><p>TODO</p><h3 id="スタッシュ-git-stash" tabindex="-1">スタッシュ (<code>git stash</code>) <a class="header-anchor" href="#スタッシュ-git-stash" aria-label="Permalink to &quot;スタッシュ (`git stash`)&quot;">​</a></h3><p>TODO</p>',42)]))}const P=e(b,[["render",f]]);export{B as __pageData,P as default};
